$script:ProtocolErrorCodes = @{ UnknownEventType='unknown_event_type'; AclViolation='acl_violation'; MissingExplicitTarget='missing_explicit_target'; AgentNotFound='agent_not_found'; DeadAgentReceived='dead_agent_received'; Inv9Violation='inv9_violation'; LockHierarchyViolation='lock_hierarchy_violation'; BusHalted='bus_halted'; HandlerException='handler_exception'; DeliveryFailed='delivery_failed' }
function New-ProtocolError { param([string]$Code,[string]$Message,[string]$AffectedAgentName=$null,[int64]$OriginalEvtId=0,[hashtable]$Context=$null); $known=$script:ProtocolErrorCodes.Values; if($Code -notin $known){throw "UnknownProtocolErrorCode: $Code"}; return @{Code=$Code;Message=$Message;AffectedAgentName=$AffectedAgentName;OriginalEvtId=$OriginalEvtId;Context=$Context;Timestamp=[DateTime]::UtcNow} }
function Get-ProtocolErrorCodes { return $script:ProtocolErrorCodes }
function Test-IsKnownProtocolErrorCode { param([string]$Code); return $script:ProtocolErrorCodes.Values -contains $Code }
